components.codeTemplate:
HStack {
    Text("Title that wins space")
        .layoutPriority({value})
    Text("Trailing")
}

VStack(alignment: .{alignment}) {
    Text("Aligned")
        .alignmentGuide(.{alignment}) { d in d[.{alignment}] + {offset} }
    Text("Reference")
}

ScrollView(.horizontal) {
    LazyHStack {
        ForEach(items) { item in
            Card(item)
                .containerRelativeFrame(.{axes}, count: {count}, span: {span}, spacing: {spacing}, alignment: .{alignment})
        }
    }
}
